---
import MenuIcon from "@lucide/astro/icons/menu"
import SearchIcon from "@lucide/astro/icons/search"
import type { ImageMetadata } from "astro"

import { Button } from "@/components/ui/button"
import {
  Command,
  CommandDialog,
  CommandEmpty,
  CommandInput,
  CommandItem,
  CommandList,
  CommandShortcut,
} from "@/components/ui/command"
import { Dialog, DialogTrigger } from "@/components/ui/dialog"
import { Header, HeaderContainer, HeaderGroup } from "@/components/ui/header"
import { Icon } from "@/components/ui/icon"
import { Layout, LayoutBody, LayoutHead } from "@/components/ui/layout"
import { Logo, LogoImage, LogoText } from "@/components/ui/logo"
import {
  NavigationMenu,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
} from "@/components/ui/navigation-menu"
import { Separator } from "@/components/ui/separator"
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet"
import { ThemeProvider, ThemeToggle } from "@/components/ui/theme-toggle"

type Props = {
  class?: string
  bodyClass?: string
  bodyStyle?: string
  name?: string
  title?: string
  description?: string
  image?: {
    src?: ImageMetadata | string
    alt?: string
  }
  noindex?: boolean
  nofollow?: boolean
  canonical?: string
  logo: {
    label: string
    href: string
    src?: any
    srcLight?: any
    srcDark?: any
    alt?: string
  }
  navigation: {
    label: string
    href: string
    links?: {
      label: string
      href: string
    }[]
  }[]
  buttons?: {
    label: string
    href: string
    icon?: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  searchItems?: {
    label: string
    href: string
    keywords?: string[]
  }[]
}

const {
  class: className,
  bodyClass,
  bodyStyle = "--container-width: 96rem",
  name,
  title,
  description,
  image,
  noindex,
  nofollow,
  canonical,
  logo,
  navigation,
  buttons = [],
  searchItems = [],
} = Astro.props
---

<Layout class={className}>
  <LayoutHead
    name={name}
    title={title}
    description={description}
    image={image}
    noindex={noindex}
    nofollow={nofollow}
    canonical={canonical}
  >
    <ThemeProvider />
  </LayoutHead>
  <LayoutBody class={bodyClass} style={bodyStyle}>
    <div class="bg-background flex min-h-svh flex-col">
      <Header>
        <HeaderContainer class="gap-4">
          <HeaderGroup>
            <Sheet>
              <SheetTrigger
                variant="ghost"
                size="icon-sm"
                class="md:hidden"
                aria-label="Open navigation"
              >
                <MenuIcon />
              </SheetTrigger>
              <SheetContent
                side="left"
                class="w-80 max-w-[calc(100vw-2rem)] p-0"
              >
                <SheetHeader class="sr-only">
                  <SheetTitle>Navigation</SheetTitle>
                </SheetHeader>
                <div class="flex h-full flex-col gap-6 p-4">
                  <Logo href={logo.href}>
                    <LogoImage
                      src={logo.src}
                      srcLight={logo.srcLight}
                      srcDark={logo.srcDark}
                      alt={logo.alt}
                    />
                    {logo.label && <LogoText>{logo.label}</LogoText>}
                  </Logo>
                  <nav class="flex flex-col gap-1">
                    {
                      navigation.map((item) => (
                        <a
                          href={item.href}
                          class="hover:bg-muted rounded-md px-2 py-2 text-sm font-medium transition-colors"
                        >
                          {item.label}
                        </a>
                      ))
                    }
                  </nav>
                  {
                    buttons.length > 0 && (
                      <div class="mt-auto flex flex-col gap-2">
                        {buttons.map(({ label, icon, ...button }) => (
                          <Button
                            as="a"
                            variant={button.variant ?? "default"}
                            target={
                              button.href.startsWith("http")
                                ? "_blank"
                                : undefined
                            }
                            rel={
                              button.href.startsWith("http")
                                ? "noreferrer"
                                : undefined
                            }
                            {...button}
                          >
                            {icon && <Icon name={icon} />}
                            {label}
                          </Button>
                        ))}
                      </div>
                    )
                  }
                </div>
              </SheetContent>
            </Sheet>
            <Logo href={logo.href}>
              <LogoImage
                src={logo.src}
                srcLight={logo.srcLight}
                srcDark={logo.srcDark}
                alt={logo.alt}
              />
              {logo.label && <LogoText>{logo.label}</LogoText>}
            </Logo>
          </HeaderGroup>
          <NavigationMenu class="hidden flex-none justify-start md:flex">
            <NavigationMenuList class="justify-start">
              {
                navigation.map((item, index) => (
                  <NavigationMenuItem value={`nav-${index}`}>
                    <NavigationMenuLink href={item.href}>
                      {item.label}
                    </NavigationMenuLink>
                  </NavigationMenuItem>
                ))
              }
            </NavigationMenuList>
          </NavigationMenu>
          <HeaderGroup class="ml-auto hidden flex-1 md:flex">
            {
              searchItems.length > 0 && (
                <Dialog class="min-w-32">
                  <DialogTrigger
                    variant="outline"
                    size="sm"
                    class="w-full justify-start shadow-none"
                  >
                    <SearchIcon data-icon="inline-start" />
                    <span class="truncate">Search</span>
                  </DialogTrigger>
                  <CommandDialog
                    title="Search pages"
                    description="Search the site and jump to a page."
                  >
                    <Command>
                      <CommandInput placeholder="Search pages..." />
                      <CommandList>
                        <CommandEmpty>No results found.</CommandEmpty>
                        {searchItems.map((item) => (
                          <CommandItem
                            href={item.href}
                            value={item.href}
                            label={item.label}
                            keywords={item.keywords}
                          >
                            {item.label}
                            <CommandShortcut>{item.href}</CommandShortcut>
                          </CommandItem>
                        ))}
                      </CommandList>
                    </Command>
                  </CommandDialog>
                </Dialog>
              )
            }
            <ThemeToggle />
            <Separator class="h-8" orientation="vertical" />
            {
              buttons.map(({ label, icon, ...button }) => (
                <Button
                  as="a"
                  size={icon && !label ? "icon-sm" : "sm"}
                  aria-label={label}
                  target={button.href.startsWith("http") ? "_blank" : undefined}
                  rel={
                    button.href.startsWith("http") ? "noreferrer" : undefined
                  }
                  {...button}
                >
                  {icon && <Icon name={icon} />}
                  {label}
                </Button>
              ))
            }
          </HeaderGroup>
        </HeaderContainer>
      </Header>
      <main class="@container flex flex-1 flex-col">
        <slot />
      </main>
      <slot name="footer" />
    </div>
  </LayoutBody>
</Layout>
